from random import random, uniform
import math

def neuron(inputs, weights, bias, activation):
    weighted_sum = bias
    for i in range(len(inputs)):
        weighted_sum += inputs[i] * weights[i]

    if activation == "sigmoid":
        return 1 / (1 + math.exp(-weighted_sum))
    elif activation == "step":
        return 1 if weighted_sum >= 0 else 0
    else:
        raise ValueError("Unsupported activation function")

def binary_classifier(dataset, weights, bias, activation):
    predictions = []
    for sample in dataset:
        output = neuron(sample, weights, bias, activation)

        if activation == "sigmoid":
            predictions.append(1 if output >= 0.5 else 0)
        else:
            predictions.append(output)
    return predictions

def create_dataset(num_samples):
    dataset = []
    for _ in range(num_samples):
        x1 = random()
        x2 = random()
        label = 1 if x1 + x2 >= 1 else 0
        dataset.append([x1, x2, label])
    return dataset

def calculate_weights(dataset, activation):
    weights = [uniform(-1, 1), uniform(-1, 1)]
    bias = uniform(-1, 1)
    learning_rate = 0.1

    for _ in range(100):
        for row in dataset:
            inputs = row[:2]
            target = row[2]

            prediction = neuron(inputs, weights, bias, activation)

            if activation == "sigmoid":
                prediction = 1 if prediction >= 0.5 else 0

            error = target - prediction

            for i in range(len(weights)):
                weights[i] += learning_rate * error * inputs[i]

            bias += learning_rate * error

    return weights, bias

# E
data = create_dataset(10)

# F
weights_sigmoid, bias_sigmoid = calculate_weights(data, "sigmoid")
weights_step, bias_step = calculate_weights(data, "step")

# G
classifier_data = [row[:2] for row in data]
pred_sigmoid = binary_classifier(classifier_data, weights_sigmoid, bias_sigmoid, "sigmoid")
pred_step = binary_classifier(classifier_data, weights_step, bias_step, "step")

print({
    "dataset": data,
    "sigmoid_weights": weights_sigmoid,
    "sigmoid_bias": bias_sigmoid,
    "step_weights": weights_step,
    "step_bias": bias_step,
    "sigmoid_predictions": pred_sigmoid,
    "step_predictions": pred_step,
})

